import{_ as i,o as c,c as t,a2 as l}from"./chunks/framework.BKchhTkY.js";const k=JSON.parse('{"title":"代码要求检查清单（check_list）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/check_list.md","filePath":"guide/check_list.md","lastUpdated":null}'),a={name:"guide/check_list.md"};function o(d,e,s,r,_,n){return c(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="代码要求检查清单-check-list" tabindex="-1">代码要求检查清单（check_list） <a class="header-anchor" href="#代码要求检查清单-check-list" aria-label="Permalink to &quot;代码要求检查清单（check_list）&quot;">​</a></h1><h2 id="编码要求" tabindex="-1">编码要求 <a class="header-anchor" href="#编码要求" aria-label="Permalink to &quot;编码要求&quot;">​</a></h2><ol><li>读取直接读结构体，写参数必须用函数</li><li>配置宏、参数宏、共用结构体、枚举的放置位置规范</li><li>检查所有回调函数签名</li><li>DRV/BSP 所有功能都要可以通过宏开启或关闭，减少 Flash/RAM 占用</li><li>DRV/BSP 所有实例用 <code>*_INSTANCE_DEF</code> 宏来定义</li><li><code>*_INSTANCE_DEF</code> 内部自带 <code>static</code>；协议缓冲区加 <code>const</code>；要用 DMA 加 <code>DMA_RAM</code></li><li>实例结构体 set 封装函数，get 直接通过结构体获取</li><li>注册、初始化函数需要检查 cfg 结构体参数</li><li>ITCM 放置：FreeRTOS 内核代码；创建的 FreeRTOS 任务代码；Kalman 等高算力代码；中断代码</li><li>检查 <code>const</code>、<code>extern</code>、<code>register</code>、<code>static</code>、<code>volatile</code></li><li>函数签名：BSP 用 register，DRV 用 init</li><li>检查每个 DRV/BSP 的所有 static 函数，不要每个 DRV 自己定义一个 clamp 限幅函数</li></ol>',3)])])}const m=i(a,[["render",o]]);export{k as __pageData,m as default};
